\paragraph{Target (long) estimand.}
Let $Y^{g_{\boldsymbol\delta}}$ denote the counterfactual outcome under the intervention that draws
$\mathbf W$ from $g_{\boldsymbol\delta}(\cdot\mid \mathbf X)$ (independently of $U$ given $\mathbf X$).
Under \eqref{eq:latent_ignorability}, the causal estimand is
\begin{equation}
\psi(\boldsymbol\delta)
:=\E\big[Y^{g_{\boldsymbol\delta}}\big]
=\E\Big[\int_{\mathcal W}\mu(\mathbf V,\mathbf w)\,g_{\boldsymbol\delta}(\mathbf w\mid \mathbf X)\,d\mathbf w\Big].
\label{eq:psi_long}
\end{equation}

perturbations.perturbed:
\paragraph{Target (long) estimand.}
Let $Y^{g_{\boldsymbol\delta}}$ denote the counterfactual outcome. Under \eqref{eq:latent_ignorability}, we define the causal estimand such that the outcome $Y$ determines the distribution of the intervention $g_{\boldsymbol\delta}(\cdot\mid \mathbf X)$:
\begin{equation}
\psi(\boldsymbol\delta)
:=\E\big[Y^{g_{\boldsymbol\delta}}\big]
=\E\Big[\int_{\mathcal W} g_{\boldsymbol\delta}(\mu(\mathbf V,\mathbf w) \mid \mathbf X)\,d\mathbf w\Big].
\label{eq:psi_long}
\end{equation}

